1	const { Pool } = require('pg');
2	
3	const pool = new Pool({
4	  connectionString: process.env.DATABASE_URL || 'postgres://taskflow:taskflow@localhost:5432/taskflow',
5	});
6	
7	async function query(text, params) {
8	  const start = Date.now();
9	  const result = await pool.query(text, params);
10	  const duration = Date.now() - start;
11	  if (duration > 500) console.warn(`Slow query (${duration}ms):`, text);
12	  return result;
13	}
14	
15	module.exports = { pool, query };
