1	const jwt = require('jsonwebtoken');
2	
3	const JWT_SECRET = process.env.JWT_SECRET;
4	
5	function auth(req, res, next) {
6	  const header = req.headers.authorization;
7	  if (!header || !header.startsWith('Bearer ')) {
8	    return res.status(401).json({ error: 'Missing or invalid authorization header' });
9	  }
10	
11	  const token = header.split(' ')[1];
12	  try {
13	    const payload = jwt.verify(token, JWT_SECRET);
14	    req.user = { id: payload.sub, email: payload.email };
15	    next();
16	  } catch (err) {
17	    return res.status(401).json({ error: 'Invalid or expired token' });
18	  }
19	}
20	
21	module.exports = auth;
