1	const express = require('express');
2	const router = express.Router();
3	const { query } = require('../db');
4	const auth = require('../middleware/auth');
5	
6	router.use(auth);
7	
8	router.get('/', async (req, res, next) => {
9	  try {
10	    const result = await query('SELECT * FROM tasks WHERE user_id = $1 ORDER BY created_at DESC', [req.user.id]);
11	    res.json(result.rows);
12	  } catch (err) { next(err); }
13	});
14	
15	router.post('/', async (req, res, next) => {
16	  try {
17	    const { title, description } = req.body;
18	    const result = await query(
19	      'INSERT INTO tasks (title, description, user_id) VALUES ($1, $2, $3) RETURNING *',
20	      [title, description, req.user.id]
21	    );
22	    res.status(201).json(result.rows[0]);
23	  } catch (err) { next(err); }
24	});
25	
26	router.put('/:id', async (req, res, next) => {
27	  try {
28	    const { title, description, status } = req.body;
29	    const result = await query(
30	      'UPDATE tasks SET title = $1, description = $2, status = $3 WHERE id = $4 AND user_id = $5 RETURNING *',
31	      [title, description, status, req.params.id, req.user.id]
32	    );
33	    if (result.rows.length === 0) return res.status(404).json({ error: 'Task not found' });
34	    res.json(result.rows[0]);
35	  } catch (err) { next(err); }
36	});
37	
38	router.delete('/:id', async (req, res, next) => {
39	  try {
40	    const result = await query('DELETE FROM tasks WHERE id = $1 AND user_id = $2 RETURNING id', [req.params.id, req.user.id]);
41	    if (result.rows.length === 0) return res.status(404).json({ error: 'Task not found' });
42	    res.status(204).end();
43	  } catch (err) { next(err); }
44	});
45	
46	module.exports = router;
