1	import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
2	import Login from './pages/Login';
3	import Dashboard from './pages/Dashboard';
4	import TaskDetail from './pages/TaskDetail';
5	import { AuthProvider, useAuth } from './context/AuthContext';
6	
7	function PrivateRoute({ children }) {
8	  const { user } = useAuth();
9	  return user ? children : <Navigate to="/login" />;
10	}
11	
12	export default function App() {
13	  return (
14	    <AuthProvider>
15	      <BrowserRouter>
16	        <Routes>
17	          <Route path="/login" element={<Login />} />
18	          <Route path="/" element={<PrivateRoute><Dashboard /></PrivateRoute>} />
19	          <Route path="/tasks/:id" element={<PrivateRoute><TaskDetail /></PrivateRoute>} />
20	        </Routes>
21	      </BrowserRouter>
22	    </AuthProvider>
23	  );
24	}
